+import com.yottastudios.ns.collabspace.shared.util.page.PageInfo;
+import com.yottastudios.ns.collabspace.workspace.entity.NodePermissionLogEntity;
+import com.yottastudios.ns.collabspace.workspace.mapper.NodePermissionLogMapper;
+import com.yottastudios.ns.collabspace.workspace.service.INodePermissionLogService;
+import com.yottastudios.ns.collabspace.workspace.vo.NodePermissionLogVo;
+import org.springframework.stereotype.Service;
+
+import java.util.Map;
+
+@Service
+public class NodePermissionLogServiceImpl
+        extends ServiceImpl<NodePermissionLogMapper, NodePermissionLogEntity>
+        implements INodePermissionLogService {
+
+    private static final Map<String, String> ROLE_DISPLAY_MAP = Map.of(
+            "manager", "可管理",
+            "editor", "可编辑",
+            "reader", "可阅读"
+    );
+
+    @Override
+    public PageInfo<NodePermissionLogVo> pageBySpaceNodeId(Long spaceNodeId, String keyword, int pageNo, int pageSize) {
+        LambdaQueryWrapper<NodePermissionLogEntity> wrapper = new LambdaQueryWrapper<>();
+        wrapper.eq(NodePermissionLogEntity::getSpaceNodeId, spaceNodeId);
+        if (StrUtil.isNotBlank(keyword)) {
+            wrapper.and(w -> w
+                    .like(NodePermissionLogEntity::getOperatorName, keyword)
+                    .or().like(NodePermissionLogEntity::getTargetName, keyword)
+                    .or().like(NodePermissionLogEntity::getNewRole, keyword)
+                    .or().like(NodePermissionLogEntity::getOldRole, keyword)
+            );
+        }
+        wrapper.orderByDesc(NodePermissionLogEntity::getCreatedAt);
+
+        IPage<NodePermissionLogEntity> page = page(new Page<>(pageNo, pageSize), wrapper);
+        IPage<NodePermissionLogVo> voPage = page.convert(this::toVo);
+        return PageHelper.build(voPage);
+    }
+
+    @Override
+    public void log(Long spaceNodeId, String spaceId, Long operatorId, String operatorName,
+                    String targetName, Integer targetType, String action, String oldRole, String newRole) {
+        NodePermissionLogEntity entity = NodePermissionLogEntity.builder()
+                .spaceNodeId(spaceNodeId)
+                .spaceId(spaceId)
+                .operatorId(operatorId)
+                .operatorName(operatorName)
+                .targetName(targetName)
+                .targetType(targetType)
+                .action(action)
+                .oldRole(oldRole)
+                .newRole(newRole)
+                .build();
+        save(entity);
+    }
+
+    private NodePermissionLogVo toVo(NodePermissionLogEntity entity) {
+        NodePermissionLogVo vo = new NodePermissionLogVo();
+        vo.setOperatorName(entity.getOperatorName());
+        vo.setCreatedAt(entity.getCreatedAt());
+        vo.setTargetName(entity.getTargetName());
+
+        String action = entity.getAction();
+        if ("remove".equals(action)) {
+            vo.setDescription("将 " + entity.getTargetName() + " 权限改为 移除所有权限");
+            vo.setNewRoleDisplay("移除所有权限");
+        } else {
+            String roleDisplay = ROLE_DISPLAY_MAP.getOrDefault(entity.getNewRole(), entity.getNewRole());
+            vo.setDescription("将 " + entity.getTargetName() + " 权限改为 " + roleDisplay);
+            vo.setNewRoleDisplay(roleDisplay);
+        }
+        return vo;
+    }
+}
