244→   244→+    public PageInfo<TeamRoleTreeVo> listTeamRoles(Long userId, String spaceId, Long spaceNodeId, String keyword, int pageNo, int pageSize) {
245→   245→+        // 1. 获取空间站小组树
246→   246→+        List<TeamMemberVo> teamTree = apitableGrpcClientService.getTeamMembers(spaceId, userId);
247→   247→+
248→   248→+        // 2. 获取当前节点的权限数据（考虑继承）
249→   249→+        Map<Long, String> teamIdToRole = getTeamRoleMap(spaceId, spaceNodeId);
250→   250→+
251→   251→+        // 3. 转换为 TeamRoleTreeVo
252→   252→+        List<TeamRoleTreeVo> tree = convertToTeamRoleTree(teamTree, teamIdToRole);
253→   253→+
254→   254→+        // 4. 搜索过滤
255→   255→+        List<TeamRoleTreeVo> result;
256→   256→+        if (StrUtil.isNotBlank(keyword)) {
257→   257→+            result = flattenAndFilter(tree, keyword);
258→   258→+        } else {
259→   259→+            result = flattenTree(tree);
260→   260→+        }
261→   261→+
262→   262→+        // 5. 内存分页
263→   263→+        int total = result.size();
264→   264→+        int fromIndex = Math.min((pageNo - 1) * pageSize, total);
265→   265→+        int toIndex = Math.min(fromIndex + pageSize, total);
266→   266→+        List<TeamRoleTreeVo> pageRecords = result.subList(fromIndex, toIndex);
267→   267→+
268→   268→+        return PageHelper.build(pageNo, pageSize, total, pageRecords);
269→   269→+    }
