271→   271→+    /**
272→   272→+     * 获取节点的小组权限映射 (teamId -> roleCode)
273→   273→+     */
274→   274→+    private Map<Long, String> getTeamRoleMap(String spaceId, Long spaceNodeId) {
275→   275→+        String controlId;
276→   276→+        if (controlService.existsByControlId(spaceNodeId.toString())) {
277→   277→+            controlId = spaceNodeId.toString();
278→   278→+        } else {
279→   279→+            Long extendNodeId = getNodeExtendNodeId(spaceNodeId);
280→   280→+            controlId = extendNodeId != null ? extendNodeId.toString() : null;
281→   281→+        }
282→   282→+
283→   283→+        if (controlId == null) {
284→   284→+            return Map.of();
285→   285→+        }
286→   286→+
287→   287→+        List<ControlRoleEntity> controlRoles = controlRoleService.getByControlId(controlId);
288→   288→+        if (CollectionUtils.isEmpty(controlRoles)) {
289→   289→+            return Map.of();
290→   290→+        }
291→   291→+
292→   292→+        List<Long> unitIds = controlRoles.stream().map(ControlRoleEntity::getUnitId).toList();
293→   293→+        List<NodeRoleUnit> unitInfos = apitableGrpcClientService.getNodeRoleUnitList(spaceId, unitIds);
294→   294→+
295→   295→+        // unitType=1 means Department/Team
296→   296→+        Map<Long, Long> unitIdToRefId = unitInfos.stream()
297→   297→+                .filter(u -> u.getUnitType() != null && u.getUnitType() == 1)
298→   298→+                .collect(Collectors.toMap(NodeRoleUnit::getUnitId, NodeRoleUnit::getUnitRefId, (a, b) -> a));
299→   299→+
300→   300→+        Map<Long, String> unitIdToRole = controlRoles.stream()
301→   301→+                .collect(Collectors.toMap(ControlRoleEntity::getUnitId, ControlRoleEntity::getRoleCode, (a, b) -> a));
302→   302→+
303→   303→+        // teamId(unitRefId) -> roleCode
304→   304→+        Map<Long, String> teamIdToRole = new HashMap<>();
305→   305→+        unitIdToRefId.forEach((unitId, teamId) -> {
306→   306→+            String role = unitIdToRole.get(unitId);
307→   307→+            if (role != null) {
308→   308→+                teamIdToRole.put(teamId, role);
309→   309→+            }
310→   310→+        });
311→   311→+        return teamIdToRole;
