313→   313→+
314→   314→+    private List<TeamRoleTreeVo> convertToTeamRoleTree(List<TeamMemberVo> teamTree, Map<Long, String> teamIdToRole) {
315→   315→+        List<TeamRoleTreeVo> result = new ArrayList<>();
316→   316→+        for (TeamMemberVo team : teamTree) {
317→   317→+            TeamRoleTreeVo vo = new TeamRoleTreeVo();
318→   318→+            vo.setTeamId(team.getTeamId());
319→   319→+            vo.setTeamName(team.getTeamName());
320→   320→+            vo.setParentId(team.getParentTeamId());
321→   321→+            vo.setMemberCount(team.getMemberCount());
322→   322→+            vo.setRole(teamIdToRole.get(team.getTeamId()));
323→   323→+            if (CollectionUtils.isNotEmpty(team.getChildrenList())) {
324→   324→+                vo.setChildren(convertToTeamRoleTree(team.getChildrenList(), teamIdToRole));
325→   325→+            } else {
326→   326→+                vo.setChildren(List.of());
327→   327→+            }
328→   328→+            result.add(vo);
329→   329→+        }
330→   330→+        return result;
331→   331→+    }
332→   332→+
333→   333→+    /** 平铺树为列表（前序遍历） */
334→   334→+    private List<TeamRoleTreeVo> flattenTree(List<TeamRoleTreeVo> tree) {
335→   335→+        List<TeamRoleTreeVo> result = new ArrayList<>();
336→   336→+        for (TeamRoleTreeVo node : tree) {
337→   337→+            result.add(node);
338→   338→+            if (CollectionUtils.isNotEmpty(node.getChildren())) {
339→   339→+                result.addAll(flattenTree(node.getChildren()));
340→   340→+            }
341→   341→+        }
342→   342→+        return result;
343→   343→+    }
344→   344→+
345→   345→+    /** 搜索过滤：按 teamName 模糊匹配，平铺返回 */
346→   346→+    private List<TeamRoleTreeVo> flattenAndFilter(List<TeamRoleTreeVo> tree, String keyword) {
347→   347→+        List<TeamRoleTreeVo> result = new ArrayList<>();
348→   348→+        String lowerKeyword = keyword.toLowerCase();
349→   349→+        for (TeamRoleTreeVo node : tree) {
350→   350→+            if (node.getTeamName() != null && node.getTeamName().toLowerCase().contains(lowerKeyword)) {
351→   351→+                result.add(node);
352→   352→+            }
353→   353→+            if (CollectionUtils.isNotEmpty(node.getChildren())) {
354→   354→+                result.addAll(flattenAndFilter(node.getChildren(), keyword));
355→   355→+            }
356→   356→+        }
357→   357→+        return result;
358→   358→+    }
