361→   361→+    public PageInfo<NodeRoleUnit> listMemberRoles(String spaceId, Long spaceNodeId, String keyword, int pageNo, int pageSize) {
362→   362→+        // 只查当前节点手动设置的权限（不含继承）
363→   363→+        String controlId = spaceNodeId.toString();
364→   364→+        List<ControlRoleEntity> controlRoles = controlRoleService.getByControlId(controlId);
365→   365→+        if (CollectionUtils.isEmpty(controlRoles)) {
366→   366→+            return PageHelper.build(pageNo, pageSize, 0, List.of());
367→   367→+        }
368→   368→+
369→   369→+        List<Long> unitIds = controlRoles.stream().map(ControlRoleEntity::getUnitId).toList();
370→   370→+        List<NodeRoleUnit> allUnits = apitableGrpcClientService.getNodeRoleUnitList(spaceId, unitIds);
371→   371→+
372→   372→+        // unitType=3 means Member
373→   373→+        Map<Long, String> unitIdToRole = controlRoles.stream()
374→   374→+                .collect(Collectors.toMap(ControlRoleEntity::getUnitId, ControlRoleEntity::getRoleCode, (a, b) -> a));
375→   375→+
376→   376→+        List<NodeRoleUnit> memberUnits = allUnits.stream()
377→   377→+                .filter(u -> u.getUnitType() != null && u.getUnitType() == 3)
378→   378→+                .peek(u -> u.setRole(unitIdToRole.get(u.getUnitId())))
379→   379→+                .toList();
380→   380→+
381→   381→+        // 搜索过滤
382→   382→+        List<NodeRoleUnit> filtered = memberUnits;
383→   383→+        if (StrUtil.isNotBlank(keyword)) {
384→   384→+            String lowerKeyword = keyword.toLowerCase();
385→   385→+            filtered = memberUnits.stream()
386→   386→+                    .filter(u -> (u.getUnitName() != null && u.getUnitName().toLowerCase().contains(lowerKeyword))
387→   387→+                            || (u.getNickName() != null && u.getNickName().toLowerCase().contains(lowerKeyword)))
388→   388→+                    .toList();
389→   389→+        }
390→   390→+
391→   391→+        // 内存分页
392→   392→+        int total = filtered.size();
393→   393→+        int fromIndex = Math.min((pageNo - 1) * pageSize, total);
394→   394→+        int toIndex = Math.min(fromIndex + pageSize, total);
395→   395→+        List<NodeRoleUnit> pageRecords = filtered.subList(fromIndex, toIndex);
396→   396→+
397→   397→+        return PageHelper.build(pageNo, pageSize, total, pageRecords);
398→   398→+    }
