274→+    private Map<Long, String> getTeamRoleMap(String spaceId, Long spaceNodeId) {
275→+        String controlId;
276→+        if (controlService.existsByControlId(spaceNodeId.toString())) {
277→+            controlId = spaceNodeId.toString();
278→+        } else {
