280→+            controlId = extendNodeId != null ? extendNodeId.toString() : null;
281→+        }
282→+
283→+        if (controlId == null) {
284→+            return Map.of();
285→+        }
286→+
287→+        List<ControlRoleEntity> controlRoles = controlRoleService.getByControlId(controlId);
288→+        if (CollectionUtils.isEmpty(controlRoles)) {
289→+            return Map.of();
290→+        }
291→+
292→+        List<Long> unitIds = controlRoles.stream().map(ControlRoleEntity::getUnitId).toList();
293→+        List<NodeRoleUnit> unitInfos = apitableGrpcClientService.getNodeRoleUnitList(spaceId, unitIds);
294→+
295→+        // unitType=1 means Department/Team
296→+        Map<Long, Long> unitIdToRefId = unitInfos.stream()
297→+                .filter(u -> u.getUnitType() != null && u.getUnitType() == 1)
298→+                .collect(Collectors.toMap(NodeRoleUnit::getUnitId, NodeRoleUnit::getUnitRefId, (a, b) -> a));
299→+
300→+        Map<Long, String> unitIdToRole = controlRoles.stream()
301→+                .collect(Collectors.toMap(ControlRoleEntity::getUnitId, ControlRoleEntity::getRoleCode, (a, b) -> a));
302→+
303→+        // teamId(unitRefId) -> roleCode
304→+        Map<Long, String> teamIdToRole = new HashMap<>();
305→+        unitIdToRefId.forEach((unitId, teamId) -> {
306→+            String role = unitIdToRole.get(unitId);
307→+            if (role != null) {
