314→+    private List<TeamRoleTreeVo> convertToTeamRoleTree(List<TeamMemberVo> teamTree, Map<Long, String> teamIdToRole) {
315→+        List<TeamRoleTreeVo> result = new ArrayList<>();
316→+        for (TeamMemberVo team : teamTree) {
317→+            TeamRoleTreeVo vo = new TeamRoleTreeVo();
318→+            vo.setTeamId(team.getTeamId());
319→+            vo.setTeamName(team.getTeamName());
320→+            vo.setParentId(team.getParentTeamId());
321→+            vo.setMemberCount(team.getMemberCount());
322→+            vo.setRole(teamIdToRole.get(team.getTeamId()));
323→+            if (CollectionUtils.isNotEmpty(team.getChildrenList())) {
324→+                vo.setChildren(convertToTeamRoleTree(team.getChildrenList(), teamIdToRole));
325→+            } else {
326→+                vo.setChildren(List.of());
327→+            }
328→+            result.add(vo);
329→+        }
330→+        return result;
331→+    }
