333→+    /** 平铺树为列表（前序遍历） */
334→+    private List<TeamRoleTreeVo> flattenTree(List<TeamRoleTreeVo> tree) {
335→+        List<TeamRoleTreeVo> result = new ArrayList<>();
336→+        for (TeamRoleTreeVo node : tree) {
337→+            result.add(node);
338→+            if (CollectionUtils.isNotEmpty(node.getChildren())) {
339→+                result.addAll(flattenTree(node.getChildren()));
340→+            }
341→+        }
342→+        return result;
343→+    }
