345→+    /** 搜索过滤：按 teamName 模糊匹配，平铺返回 */
346→+    private List<TeamRoleTreeVo> flattenAndFilter(List<TeamRoleTreeVo> tree, String keyword) {
347→+        List<TeamRoleTreeVo> result = new ArrayList<>();
348→+        String lowerKeyword = keyword.toLowerCase();
349→+        for (TeamRoleTreeVo node : tree) {
350→+            if (node.getTeamName() != null && node.getTeamName().toLowerCase().contains(lowerKeyword)) {
351→+                result.add(node);
352→+            }
353→+            if (CollectionUtils.isNotEmpty(node.getChildren())) {
354→+                result.addAll(flattenAndFilter(node.getChildren(), keyword));
355→+            }
356→+        }
357→+        return result;
358→+    }
