531→+    private EditRoleResultVo checkMemberTeamConflict(String spaceId, Long spaceNodeId, String newRole, List<Long> unitIds) {
532→+        List<NodeRoleUnit> unitInfos = apitableGrpcClientService.getNodeRoleUnitList(spaceId, unitIds);
533→+        List<NodeRoleUnit> memberUnits = unitInfos.stream()
534→+                .filter(u -> u.getUnitType() != null && u.getUnitType() == 3)
535→+                .toList();
536→+
537→+        if (memberUnits.isEmpty()) {
538→+            return EditRoleResultVo.noConflict();
539→+        }
540→+
541→+        NodeRoleLevel newLevel = NodeRoleLevel.fromRoleTag(newRole);
542→+
543→+        for (NodeRoleUnit memberUnit : memberUnits) {
544→+            Long memberUserId = memberUnit.getUnitRefId();
545→+            List<Long> memberAllUnitIds = apitableGrpcClientService.getUnitsByMember(memberUserId, spaceId);
546→+
547→+            if (CollectionUtils.isEmpty(memberAllUnitIds)) continue;
548→+            List<ControlRoleEntity> teamRoles = controlRoleService.getByControlIdAndUnitIds(spaceNodeId.toString(), memberAllUnitIds);
549→ 
550→+            for (ControlRoleEntity teamRole : teamRoles) {
551→+                if (unitIds.contains(teamRole.getUnitId())) continue;
552→+                NodeRoleLevel teamLevel = NodeRoleLevel.fromRoleTag(teamRole.getRoleCode());
553→+                if (teamLevel.getLevel() > newLevel.getLevel()) {
554→+                    List<NodeRoleUnit> teamInfos = apitableGrpcClientService.getNodeRoleUnitList(spaceId, List.of(teamRole.getUnitId()));
555→+                    String teamName = CollectionUtils.isNotEmpty(teamInfos) ? teamInfos.getFirst().getUnitName() : "未知小组";
556→+                    String teamRoleDisplay = ROLE_DISPLAY_MAP.getOrDefault(teamRole.getRoleCode(), teamRole.getRoleCode());
557→ 
558→+                    return EditRoleResultVo.builder()
559→+                            .hasConflict(true)
560→+                            .conflictTeamName(teamName)
561→+                            .conflictTeamRole(teamRole.getRoleCode())
562→+                            .conflictMessage("因为用户所处的组对文档有" + teamRoleDisplay + "权限，所以本次操作后用户依旧对文档有"
563→+                                    + teamRoleDisplay + "权限，如果想要彻底改变用户权限，请将用户移出所在组，或改变其所在组权限")
564→+                            .build();
565→+                }
566→+            }
567→+        }
568→+        return EditRoleResultVo.noConflict();
569→+    }
570→+
571→+    /** 记录权限变更日志（新增场景） */
572→+    private void logPermissionChange(Long userId, String spaceId, Long spaceNodeId, List<Long> unitIds,
573→+                                      String action, String oldRole, String newRole) {
574→+        String operatorName = getOperatorName(userId, spaceId);
575→+        List<NodeRoleUnit> unitInfos = apitableGrpcClientService.getNodeRoleUnitList(spaceId, unitIds);
576→+        for (NodeRoleUnit unit : unitInfos) {
577→+            nodePermissionLogService.log(spaceNodeId, spaceId, userId, operatorName,
578→+                    unit.getUnitName(), unit.getUnitType(), action, oldRole, newRole);
579→+        }
580→+    }
581→+
582→+    /** 记录权限变更日志（编辑场景，带旧角色映射） */
583→+    private void logPermissionChangeWithOldRoles(Long userId, String spaceId, Long spaceNodeId,
584→+                                                  List<Long> unitIds, String newRole, Map<Long, String> oldRoleMap) {
585→+        String operatorName = getOperatorName(userId, spaceId);
586→+        List<NodeRoleUnit> unitInfos = apitableGrpcClientService.getNodeRoleUnitList(spaceId, unitIds);
587→+        for (NodeRoleUnit unit : unitInfos) {
588→+            String oldRole = oldRoleMap.get(unit.getUnitId());
