696→+@Service
697→+public class NodePermissionLogServiceImpl
698→+        extends ServiceImpl<NodePermissionLogMapper, NodePermissionLogEntity>
699→+        implements INodePermissionLogService {
700→+
701→+    private static final Map<String, String> ROLE_DISPLAY_MAP = Map.of(
702→+            "manager", "可管理",
703→+            "editor", "可编辑",
704→+            "reader", "可阅读"
705→+    );
706→+
707→+    @Override
708→+    public PageInfo<NodePermissionLogVo> pageBySpaceNodeId(Long spaceNodeId, String keyword, int pageNo, int pageSize) {
709→+        LambdaQueryWrapper<NodePermissionLogEntity> wrapper = new LambdaQueryWrapper<>();
710→+        wrapper.eq(NodePermissionLogEntity::getSpaceNodeId, spaceNodeId);
711→+        if (StrUtil.isNotBlank(keyword)) {
712→+            wrapper.and(w -> w
713→+                    .like(NodePermissionLogEntity::getOperatorName, keyword)
714→+                    .or().like(NodePermissionLogEntity::getTargetName, keyword)
715→+                    .or().like(NodePermissionLogEntity::getNewRole, keyword)
716→+                    .or().like(NodePermissionLogEntity::getOldRole, keyword)
717→+            );
718→+        }
719→+        wrapper.orderByDesc(NodePermissionLogEntity::getCreatedAt);
720→+
721→+        IPage<NodePermissionLogEntity> page = page(new Page<>(pageNo, pageSize), wrapper);
722→+        IPage<NodePermissionLogVo> voPage = page.convert(this::toVo);
723→+        return PageHelper.build(voPage);
724→+    }
725→+
726→+    @Override
727→+    public void log(Long spaceNodeId, String spaceId, Long operatorId, String operatorName,
728→+                    String targetName, Integer targetType, String action, String oldRole, String newRole) {
729→+        NodePermissionLogEntity entity = NodePermissionLogEntity.builder()
730→+                .spaceNodeId(spaceNodeId)
731→+                .spaceId(spaceId)
732→+                .operatorId(operatorId)
733→+                .operatorName(operatorName)
734→+                .targetName(targetName)
735→+                .targetType(targetType)
736→+                .action(action)
737→+                .oldRole(oldRole)
738→+                .newRole(newRole)
739→+                .build();
740→+        save(entity);
741→+    }
742→+
743→+    private NodePermissionLogVo toVo(NodePermissionLogEntity entity) {
744→+        NodePermissionLogVo vo = new NodePermissionLogVo();
745→+        vo.setOperatorName(entity.getOperatorName());
746→+        vo.setCreatedAt(entity.getCreatedAt());
747→+        vo.setTargetName(entity.getTargetName());
748→+
749→+        String action = entity.getAction();
750→+        if ("remove".equals(action)) {
751→+            vo.setDescription("将 " + entity.getTargetName() + " 权限改为 移除所有权限");
752→+            vo.setNewRoleDisplay("移除所有权限");
753→+        } else {
754→+            String roleDisplay = ROLE_DISPLAY_MAP.getOrDefault(entity.getNewRole(), entity.getNewRole());
755→+            vo.setDescription("将 " + entity.getTargetName() + " 权限改为 " + roleDisplay);
756→+            vo.setNewRoleDisplay(roleDisplay);
757→+        }
758→+        return vo;
759→+    }
760→+}
