package com.yottastudios.ns.collabspace.control.infrastructure.role;

import lombok.Getter;

@Getter
public enum NodeRoleLevel {
    NONE(0),
    READER(1),
    EDITOR(2),
    MANAGER(3);

    private final int level;

    NodeRoleLevel(int level) {
        this.level = level;
    }

    public static NodeRoleLevel fromRoleTag(String roleTag) {
        if (roleTag == null) {
            return NONE;
        }

        return switch (roleTag) {
            case RoleConstants.SpaceNode.MANAGER -> MANAGER;
            case RoleConstants.SpaceNode.EDITOR -> EDITOR;
            case RoleConstants.SpaceNode.READER -> READER;
            default -> NONE;
        };
    }

    public static NodeRoleLevel fromRole(ControlRole role) {
        if (role == null) {
            return NodeRoleLevel.NONE;
        }
        return NodeRoleLevel.fromRoleTag(role.getRoleTag());
    }

    public static NodeRoleLevel fromLevel(Integer level) {
        if (level == null) {
            return NONE;
        }
        return switch (level) {
            case 1 -> READER;
            case 2 -> EDITOR;
            case 3 -> MANAGER;
            default -> NONE;
        };
    }

    public ControlRole toControlRole() {
        return switch (this) {
            case READER -> new NodeReaderRole();
            case EDITOR -> new NodeEditorRole();
            case MANAGER -> new NodeManagerRole();
            default -> null;
        };
    }

}

