16→import java.util.Map;
17→
18→@Service
19→public class NodePermissionLogServiceImpl
20→        extends ServiceImpl<NodePermissionLogMapper, NodePermissionLogEntity>
21→        implements INodePermissionLogService {
22→
23→    private static final Map<String, String> ROLE_DISPLAY_MAP = Map.of(
24→            "manager", "可管理",
25→            "editor", "可编辑",
26→            "reader", "可阅读"
27→    );
28→
29→    @Override
30→    public PageInfo<NodePermissionLogVo> pageBySpaceNodeId(Long spaceNodeId, String keyword, int pageNo, int pageSize) {
31→        LambdaQueryWrapper<NodePermissionLogEntity> wrapper = new LambdaQueryWrapper<>();
32→        wrapper.eq(NodePermissionLogEntity::getSpaceNodeId, spaceNodeId);
33→        if (StrUtil.isNotBlank(keyword)) {
34→            wrapper.and(w -> w
35→                    .like(NodePermissionLogEntity::getOperatorName, keyword)
36→                    .or().like(NodePermissionLogEntity::getTargetName, keyword)
37→                    .or().like(NodePermissionLogEntity::getNewRole, keyword)
38→                    .or().like(NodePermissionLogEntity::getOldRole, keyword)
39→            );
40→        }
41→        wrapper.orderByDesc(NodePermissionLogEntity::getCreatedAt);
42→
