244→    @Override
245→    public PageInfo<TeamRoleTreeVo> listTeamRoles(Long userId, String spaceId, Long spaceNodeId, String keyword, int pageNo, int pageSize) {
246→        // 1. 获取空间站小组树
247→        List<TeamMemberVo> teamTree = apitableGrpcClientService.getTeamMembers(spaceId, userId);
248→
249→        // 2. 获取当前节点的权限数据（考虑继承）
250→        Map<Long, String> teamIdToRole = getTeamRoleMap(spaceId, spaceNodeId);
251→
252→        // 3. 转换为 TeamRoleTreeVo
253→        List<TeamRoleTreeVo> tree = convertToTeamRoleTree(teamTree, teamIdToRole);
254→
255→        // 4. 搜索过滤
256→        List<TeamRoleTreeVo> result;
257→        if (StrUtil.isNotBlank(keyword)) {
258→            result = flattenAndFilter(tree, keyword);
259→        } else {
260→            result = flattenTree(tree);
261→        }
262→
263→        // 5. 内存分页
264→        int total = result.size();
265→        int fromIndex = Math.min((pageNo - 1) * pageSize, total);
266→        int toIndex = Math.min(fromIndex + pageSize, total);
267→        List<TeamRoleTreeVo> pageRecords = result.subList(fromIndex, toIndex);
268→
269→        return PageHelper.build(pageNo, pageSize, total, pageRecords);
270→    }
