272→    /**
273→     * 获取节点的小组权限映射 (teamId -> roleCode)
274→     */
275→    private Map<Long, String> getTeamRoleMap(String spaceId, Long spaceNodeId) {
276→        String controlId;
277→        if (controlService.existsByControlId(spaceNodeId.toString())) {
278→            controlId = spaceNodeId.toString();
279→        } else {
280→            Long extendNodeId = getNodeExtendNodeId(spaceNodeId);
281→            controlId = extendNodeId != null ? extendNodeId.toString() : null;
282→        }
283→
284→        if (controlId == null) {
285→            return Map.of();
286→        }
287→
288→        List<ControlRoleEntity> controlRoles = controlRoleService.getByControlId(controlId);
289→        if (CollectionUtils.isEmpty(controlRoles)) {
290→            return Map.of();
291→        }
292→
293→        List<Long> unitIds = controlRoles.stream().map(ControlRoleEntity::getUnitId).toList();
294→        List<NodeRoleUnit> unitInfos = apitableGrpcClientService.getNodeRoleUnitList(spaceId, unitIds);
295→
296→        // unitType=1 means Department/Team
297→        Map<Long, Long> unitIdToRefId = unitInfos.stream()
298→                .filter(u -> u.getUnitType() != null && u.getUnitType() == 1)
299→                .collect(Collectors.toMap(NodeRoleUnit::getUnitId, NodeRoleUnit::getUnitRefId, (a, b) -> a));
300→
301→        Map<Long, String> unitIdToRole = controlRoles.stream()
302→                .collect(Collectors.toMap(ControlRoleEntity::getUnitId, ControlRoleEntity::getRoleCode, (a, b) -> a));
303→
304→        // teamId(unitRefId) -> roleCode
305→        Map<Long, String> teamIdToRole = new HashMap<>();
306→        unitIdToRefId.forEach((unitId, teamId) -> {
307→            String role = unitIdToRole.get(unitId);
308→            if (role != null) {
309→                teamIdToRole.put(teamId, role);
310→            }
311→        });
312→        return teamIdToRole;
313→    }
314→
315→    private List<TeamRoleTreeVo> convertToTeamRoleTree(List<TeamMemberVo> teamTree, Map<Long, String> teamIdToRole) {
316→        List<TeamRoleTreeVo> result = new ArrayList<>();
317→        for (TeamMemberVo team : teamTree) {
318→            TeamRoleTreeVo vo = new TeamRoleTreeVo();
319→            vo.setTeamId(team.getTeamId());
320→            vo.setTeamName(team.getTeamName());
321→            vo.setParentId(team.getParentTeamId());
322→            vo.setMemberCount(team.getMemberCount());
323→            vo.setRole(teamIdToRole.get(team.getTeamId()));
324→            if (CollectionUtils.isNotEmpty(team.getChildrenList())) {
325→                vo.setChildren(convertToTeamRoleTree(team.getChildrenList(), teamIdToRole));
326→            } else {
327→                vo.setChildren(List.of());
328→            }
329→            result.add(vo);
330→        }
331→        return result;
332→    }
333→
334→    /** 平铺树为列表（前序遍历） */
335→    private List<TeamRoleTreeVo> flattenTree(List<TeamRoleTreeVo> tree) {
336→        List<TeamRoleTreeVo> result = new ArrayList<>();
337→        for (TeamRoleTreeVo node : tree) {
338→            result.add(node);
339→            if (CollectionUtils.isNotEmpty(node.getChildren())) {
340→                result.addAll(flattenTree(node.getChildren()));
341→            }
342→        }
343→        return result;
344→    }
345→
346→    /** 搜索过滤：按 teamName 模糊匹配，平铺返回 */
347→    private List<TeamRoleTreeVo> flattenAndFilter(List<TeamRoleTreeVo> tree, String keyword) {
348→        List<TeamRoleTreeVo> result = new ArrayList<>();
349→        String lowerKeyword = keyword.toLowerCase();
350→        for (TeamRoleTreeVo node : tree) {
351→            if (node.getTeamName() != null && node.getTeamName().toLowerCase().contains(lowerKeyword)) {
352→                result.add(node);
353→            }
354→            if (CollectionUtils.isNotEmpty(node.getChildren())) {
355→                result.addAll(flattenAndFilter(node.getChildren(), keyword));
356→            }
357→        }
358→        return result;
359→    }
