361→    @Override
362→    public PageInfo<NodeRoleUnit> listMemberRoles(String spaceId, Long spaceNodeId, String keyword, int pageNo, int pageSize) {
363→        // 只查当前节点手动设置的权限（不含继承）
364→        String controlId = spaceNodeId.toString();
365→        List<ControlRoleEntity> controlRoles = controlRoleService.getByControlId(controlId);
366→        if (CollectionUtils.isEmpty(controlRoles)) {
367→            return PageHelper.build(pageNo, pageSize, 0, List.of());
368→        }
369→
370→        List<Long> unitIds = controlRoles.stream().map(ControlRoleEntity::getUnitId).toList();
371→        List<NodeRoleUnit> allUnits = apitableGrpcClientService.getNodeRoleUnitList(spaceId, unitIds);
372→
373→        // unitType=3 means Member
374→        Map<Long, String> unitIdToRole = controlRoles.stream()
375→                .collect(Collectors.toMap(ControlRoleEntity::getUnitId, ControlRoleEntity::getRoleCode, (a, b) -> a));
376→
377→        List<NodeRoleUnit> memberUnits = allUnits.stream()
378→                .filter(u -> u.getUnitType() != null && u.getUnitType() == 3)
379→                .peek(u -> u.setRole(unitIdToRole.get(u.getUnitId())))
380→                .toList();
381→
382→        // 搜索过滤
383→        List<NodeRoleUnit> filtered = memberUnits;
384→        if (StrUtil.isNotBlank(keyword)) {
385→            String lowerKeyword = keyword.toLowerCase();
386→            filtered = memberUnits.stream()
387→                    .filter(u -> (u.getUnitName() != null && u.getUnitName().toLowerCase().contains(lowerKeyword))
388→                            || (u.getNickName() != null && u.getNickName().toLowerCase().contains(lowerKeyword)))
389→                    .toList();
390→        }
391→
392→        // 内存分页
393→        int total = filtered.size();
394→        int fromIndex = Math.min((pageNo - 1) * pageSize, total);
395→        int toIndex = Math.min(fromIndex + pageSize, total);
396→        List<NodeRoleUnit> pageRecords = filtered.subList(fromIndex, toIndex);
397→
398→        return PageHelper.build(pageNo, pageSize, total, pageRecords);
