package com.yottastudios.ns.collabspace.workspace.controller;

import com.yottastudios.ns.collabspace.control.infrastructure.ControlRoleDict;
import com.yottastudios.ns.collabspace.control.check.PermissionChecker;
import com.yottastudios.ns.collabspace.control.infrastructure.role.RoleConstants;
import com.yottastudios.ns.collabspace.core.support.ResponseData;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.ApiResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.GetResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.PostResource;
import com.yottastudios.ns.collabspace.shared.constants.ParamsConstants;
import com.yottastudios.ns.collabspace.shared.context.SessionContext;
import com.yottastudios.ns.collabspace.shared.holder.SpaceHolder;
import com.yottastudios.ns.collabspace.workspace.manager.query.NodeRoleQueryManager;
import com.yottastudios.ns.collabspace.workspace.manager.update.NodeRoleUpdateManager;
import com.yottastudios.ns.collabspace.workspace.ro.*;
import com.yottastudios.ns.collabspace.shared.util.page.PageInfo;
import com.yottastudios.ns.collabspace.workspace.ro.PageSearchRo;
import com.yottastudios.ns.collabspace.workspace.service.INodePermissionLogService;
import com.yottastudios.ns.collabspace.workspace.vo.EditRoleResultVo;
import com.yottastudios.ns.collabspace.workspace.vo.NodeCollaboratorsVo;
import com.yottastudios.ns.collabspace.workspace.vo.NodePermissionLogVo;
import com.yottastudios.ns.collabspace.workspace.vo.NodeRoleUnit;
import com.yottastudios.ns.collabspace.workspace.vo.TeamRoleTreeVo;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.Parameter;
import io.swagger.v3.oas.annotations.Parameters;
import io.swagger.v3.oas.annotations.enums.ParameterIn;
import io.swagger.v3.oas.annotations.media.Schema;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.annotation.Resource;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.validation.annotation.Validated;
import org.springframework.web.bind.annotation.*;

import java.util.List;

@Tag(name = "Node - Permission Api")
@RestController
@ApiResource(path = "/node/role")
@Slf4j
@RequiredArgsConstructor
@Validated
public class NodeRoleController {

    @Resource
    private NodeRoleQueryManager nodeRoleQueryManager;

    @Resource
    private NodeRoleUpdateManager nodeRoleUpdateManager;

    @Resource
    private PermissionChecker permissionChecker;

    @Resource
    private INodePermissionLogService nodePermissionLogService;

    @GetResource(path = "/{spaceNodeId}/listRole")
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "List node roles")
    public ResponseData<NodeCollaboratorsVo> listRoles(@PathVariable Long spaceNodeId) {
        // listRole should not limit permission
        Long userId = SessionContext.getUserId();
        String spaceId = SpaceHolder.get();
        return ResponseData.success(nodeRoleQueryManager.getNodeRoles(userId, spaceId, spaceNodeId));
    }

    @PostResource(path = "/addRole", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Add node role")
    public ResponseData<Void> addRole(@RequestBody @Valid AddNodeRoleRo ro) {
        Long userId = SessionContext.getUserId();
        String spaceId = SpaceHolder.get();
        //pre-check current operator has permission and unit ids in current space
        nodeRoleQueryManager.checkInSpace(spaceId, ro.getUnitIds());
        permissionChecker.requireUser(userId).onNode(ro.getSpaceNodeId()).needRole(RoleConstants.SpaceNode.MANAGER);
        nodeRoleUpdateManager.addNodeRole(userId, spaceId, ro.getSpaceNodeId(), ro.getRole(), ro.getUnitIds());

        // todo 权限同步给apitable或者apitable从aio取权限
        return ResponseData.success();
    }

    @PostResource(path = "/editRole", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Edit node role")
    public ResponseData<EditRoleResultVo> editRole(@RequestBody @Valid ModifyNodeRoleRo ro) {
        String spaceId = SpaceHolder.get();
        Long userId = SessionContext.getUserId();
        //pre-check current operator has permission and unit ids in current space
        nodeRoleQueryManager.checkInSpace(spaceId, List.of(ro.getUnitId()));
        permissionChecker.requireUser(userId).onNode(ro.getSpaceNodeId()).needRole(RoleConstants.SpaceNode.MANAGER);
        EditRoleResultVo result = nodeRoleUpdateManager.updateNodeRole(userId, spaceId, ro.getSpaceNodeId(), ro.getRole(), List.of(ro.getUnitId()));
        return ResponseData.success(result);
    }

    @PostResource(path = "/batchEditRole", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Batch edit node role")
    public ResponseData<EditRoleResultVo> batchEditRole(@RequestBody @Valid BatchModifyNodeRoleRo ro) {
        String spaceId = SpaceHolder.get();
        Long userId = SessionContext.getUserId();
        //pre-check current operator has permission and unit ids in current space
        nodeRoleQueryManager.checkInSpace(spaceId, ro.getUnitIds());
        permissionChecker.requireUser(userId).onNode(ro.getSpaceNodeId()).needRole(RoleConstants.SpaceNode.MANAGER);
        EditRoleResultVo result = nodeRoleUpdateManager.updateNodeRole(userId, spaceId, ro.getSpaceNodeId(), ro.getRole(), ro.getUnitIds());
        return ResponseData.success(result);
    }

    @PostResource(path = "/deleteRole", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Delete node role")
    public ResponseData<Void> deleteRole(@RequestBody @Valid DeleteNodeRoleRo ro) {
        String spaceId = SpaceHolder.get();
        Long userId = SessionContext.getUserId();
        //pre-check current operator has permission and unit ids in current space
        nodeRoleQueryManager.checkInSpace(spaceId, List.of(ro.getUnitId()));
        permissionChecker.requireUser(userId).onNode(ro.getSpaceNodeId()).needRole(RoleConstants.SpaceNode.MANAGER);
        nodeRoleUpdateManager.deleteNodeRoles(spaceId, ro.getSpaceNodeId(), List.of(ro.getUnitId()));
        return ResponseData.success();
    }

    @PostResource(path = "/batchDeleteRole", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Delete node role batch")
    public ResponseData<Void> batchDeleteRole(@RequestBody @Valid BatchDeleteNodeRoleRo ro) {
        Long userId = SessionContext.getUserId();
        String spaceId = SpaceHolder.get();
        //pre-check current operator has permission and unit ids in current space
        nodeRoleQueryManager.checkInSpace(spaceId, ro.getUnitIds());
        permissionChecker.requireUser(userId).onNode(ro.getSpaceNodeId()).needRole(RoleConstants.SpaceNode.MANAGER);
        nodeRoleUpdateManager.deleteNodeRoles(spaceId, ro.getSpaceNodeId(), ro.getUnitIds());
        return ResponseData.success();
    }

    @PostResource(path = "/{spaceNodeId}/disableRoleExtend", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Disable node role extend")
    public ResponseData<Void> disableRoleExtend(@PathVariable Long spaceNodeId) {
        Long userId = SessionContext.getUserId();
        String spaceId = SpaceHolder.get();
        // 禁用角色继承的本质就是新建一个 control，此时需要额外检查权限
        permissionChecker.requireUser(userId).onNode(spaceNodeId).needRole(RoleConstants.SpaceNode.MANAGER);
        // 断开继承关系的时候，需要 copy 上级节点的权限
        nodeRoleUpdateManager.enableNodeRoleIfNotExist(userId, spaceId, spaceNodeId, true);
        return ResponseData.success();
    }

    @PostResource(path = "/{spaceNodeId}/enableRoleExtend", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Enable node role extend")
    public ResponseData<Void> enableRoleExtend(@PathVariable Long spaceNodeId) {
        Long userId = SessionContext.getUserId();
        String spaceId = SpaceHolder.get();
        permissionChecker.requireUser(userId).onNode(spaceNodeId).needRole(RoleConstants.SpaceNode.MANAGER);
        nodeRoleUpdateManager.disableNodeRole(spaceId, spaceNodeId);
        return ResponseData.success();
    }

    @GetResource(path = "/{spaceNodeId}/listTeamRoles")
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "List team roles for a node (tree structure with pagination)")
    public ResponseData<PageInfo<TeamRoleTreeVo>> listTeamRoles(
            @PathVariable Long spaceNodeId,
            @Valid PageSearchRo ro) {
        Long userId = SessionContext.getUserId();
        String spaceId = SpaceHolder.get();
        return ResponseData.success(nodeRoleQueryManager.listTeamRoles(userId, spaceId, spaceNodeId,
                ro.getKeyword(), ro.getPageNo(), ro.getPageSize()));
    }

    @GetResource(path = "/{spaceNodeId}/listMemberRoles")
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "List member roles for a node (only manually set, with pagination)")
    public ResponseData<PageInfo<NodeRoleUnit>> listMemberRoles(
            @PathVariable Long spaceNodeId,
            @Valid PageSearchRo ro) {
        String spaceId = SpaceHolder.get();
        return ResponseData.success(nodeRoleQueryManager.listMemberRoles(spaceId, spaceNodeId,
                ro.getKeyword(), ro.getPageNo(), ro.getPageSize()));
    }

    @GetResource(path = "/{spaceNodeId}/permissionLogs")
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "List permission change logs for a node")
    public ResponseData<PageInfo<NodePermissionLogVo>> listPermissionLogs(
            @PathVariable Long spaceNodeId,
            @Valid PageSearchRo ro) {
        return ResponseData.success(nodePermissionLogService.pageBySpaceNodeId(spaceNodeId,
                ro.getKeyword(), ro.getPageNo(), ro.getPageSize()));
    }

    @PostResource(path = "/getAppNodesRole", requiredPermission = false)
    @Operation(summary = "Get Third App nodes role")
    public ResponseData<ControlRoleDict> getAppNodesRole(@RequestBody @Valid GetAppNodesRoleRo ro) {
        Long userId = SessionContext.getUserId();
        return ResponseData.success(nodeRoleQueryManager.getAppNodesRole(ro, userId));
    }

    @PostResource(path = "/share/getShareRole", requiredPermission = false)
    @Operation(summary = "Get user's role for a given shareId")
    public ResponseData<ControlRoleDict> getShareRole(@RequestBody @Valid GetShareRoleRo ro) {
        Long userId = SessionContext.getUserId();
        return ResponseData.success(nodeRoleQueryManager.getShareRole(ro.getShareId(), userId));
    }
}

