 71→
 72→    @Override
 73→    @Transactional
 74→    public void addNodeRole(Long userId, String spaceId, Long spaceNodeId, String role, List<Long> unitIds) {
 75→        log.info("[1822-PermApply] addNodeRole spaceNodeId={} role={} unitIds={} userId={}", spaceNodeId, role, unitIds, userId);
 76→        spaceNodeService.checkSpaceNodeExist(spaceNodeId);
 77→        enableNodeRoleIfNotExist(userId, spaceId, spaceNodeId, true);
 78→        controlRoleService.saveOrUpdateControlRole(userId, spaceNodeId.toString(), unitIds, role);
 79→        publishNodePolicyChangeEvent(spaceId, spaceNodeId, unitIds, role);
 80→        log.info("[1822-PermApply] addNodeRole done spaceNodeId={} role={} unitIds={}", spaceNodeId, role, unitIds);
 81→        // 记录权限变更日志
 82→        logPermissionChange(userId, spaceId, spaceNodeId, unitIds, "set", null, role);
 83→    }
 84→
 85→    @Override
 86→    @Transactional
 87→    public EditRoleResultVo updateNodeRole(Long userId, String spaceId, Long spaceNodeId, String role, List<Long> unitIds) {
 88→        spaceNodeService.checkSpaceNodeExist(spaceNodeId);
 89→        enableNodeRoleIfNotExist(userId, spaceId, spaceNodeId, false);
 90→
 91→        // 记录旧角色用于日志
 92→        List<ControlRoleEntity> oldRoles = controlRoleService.getByControlIdAndUnitIds(spaceNodeId.toString(), unitIds);
 93→        Map<Long, String> oldRoleMap = oldRoles.stream()
 94→                .collect(Collectors.toMap(ControlRoleEntity::getUnitId, ControlRoleEntity::getRoleCode, (a, b) -> a));
 95→
 96→        controlRoleService.saveOrUpdateControlRole(userId, spaceNodeId.toString(), unitIds, role);
 97→        publishNodePolicyChangeEvent(spaceId, spaceNodeId, unitIds, role);
 98→
 99→        // 记录权限变更日志
100→        logPermissionChangeWithOldRoles(userId, spaceId, spaceNodeId, unitIds, role, oldRoleMap);
101→
102→        // 权限冲突校验
103→        return checkMemberTeamConflict(spaceId, spaceNodeId, role, unitIds);
104→    }
105→
106→    @Override
107→    @Transactional
108→    public void enableNodeRoleIfNotExist(Long userId, String spaceId, Long spaceNodeId, boolean includeExtend) {
109→        if (controlService.existsByControlId(spaceNodeId.toString())) {
110→            log.info("Node role already exists, spaceId: {}, spaceNodeId: {}",spaceId, spaceNodeId);
111→            return;
112→        }
113→
114→        if (includeExtend) {
115→            // copy parent roles to this node
116→            Map<String, Set<Long>> roleToUnitIds = getParentRoleToUnitIds(spaceId, spaceNodeId);
117→            roleToUnitIds.forEach((role, unitIds) ->
118→                    controlRoleService.saveOrUpdateControlRole(userId, spaceNodeId.toString(), new ArrayList<>(unitIds), role));
119→        }
120→        controlService.create(userId, spaceId, spaceNodeId.toString(), ControlType.SPACE_NODE);
121→        publishNodePolicyChangeEvent(spaceId, spaceNodeId, null, null);
122→    }
