132→    public void deleteNodeRoles(String spaceId, Long spaceNodeId, List<Long> unitIds) {
133→        // 记录旧角色用于日志
134→        List<ControlRoleEntity> oldRoles = controlRoleService.getByControlIdAndUnitIds(spaceNodeId.toString(), unitIds);
135→        Map<Long, String> oldRoleMap = oldRoles.stream()
