import com.yottastudios.ns.collabspace.workspace.ro.*;
import com.yottastudios.ns.collabspace.shared.util.page.PageInfo;
import com.yottastudios.ns.collabspace.workspace.ro.PageSearchRo;
import com.yottastudios.ns.collabspace.workspace.service.INodePermissionLogService;
import com.yottastudios.ns.collabspace.workspace.vo.EditRoleResultVo;
import com.yottastudios.ns.collabspace.workspace.vo.NodeCollaboratorsVo;
import com.yottastudios.ns.collabspace.workspace.vo.NodePermissionLogVo;
import com.yottastudios.ns.collabspace.workspace.vo.NodeRoleUnit;
import com.yottastudios.ns.collabspace.workspace.vo.TeamRoleTreeVo;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.Parameter;
import io.swagger.v3.oas.annotations.Parameters;
import io.swagger.v3.oas.annotations.enums.ParameterIn;
