import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.validation.annotation.Validated;
import org.springframework.web.bind.annotation.*;

import java.util.List;

@Tag(name = "Node - Permission Api")
@RestController
@ApiResource(path = "/node/role")
@Slf4j
@RequiredArgsConstructor
@Validated
public class NodeRoleController {

    @Resource
    private NodeRoleQueryManager nodeRoleQueryManager;

    @Resource
    private NodeRoleUpdateManager nodeRoleUpdateManager;

    @Resource
    private PermissionChecker permissionChecker;

    @Resource
    private INodePermissionLogService nodePermissionLogService;

    @GetResource(path = "/{spaceNodeId}/listRole")
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "List node roles")
    public ResponseData<NodeCollaboratorsVo> listRoles(@PathVariable Long spaceNodeId) {
        // listRole should not limit permission
        Long userId = SessionContext.getUserId();
        String spaceId = SpaceHolder.get();
        return ResponseData.success(nodeRoleQueryManager.getNodeRoles(userId, spaceId, spaceNodeId));
    }

    @PostResource(path = "/addRole", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Add node role")
    public ResponseData<Void> addRole(@RequestBody @Valid AddNodeRoleRo ro) {
        Long userId = SessionContext.getUserId();
        String spaceId = SpaceHolder.get();
        //pre-check current operator has permission and unit ids in current space
        nodeRoleQueryManager.checkInSpace(spaceId, ro.getUnitIds());
        permissionChecker.requireUser(userId).onNode(ro.getSpaceNodeId()).needRole(RoleConstants.SpaceNode.MANAGER);
        nodeRoleUpdateManager.addNodeRole(userId, spaceId, ro.getSpaceNodeId(), ro.getRole(), ro.getUnitIds());

        // todo 权限同步给apitable或者apitable从aio取权限
        return ResponseData.success();
    }

    @PostResource(path = "/editRole", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Edit node role")
    public ResponseData<EditRoleResultVo> editRole(@RequestBody @Valid ModifyNodeRoleRo ro) {
        String spaceId = SpaceHolder.get();
        Long userId = SessionContext.getUserId();
        //pre-check current operator has permission and unit ids in current space
        nodeRoleQueryManager.checkInSpace(spaceId, List.of(ro.getUnitId()));
        permissionChecker.requireUser(userId).onNode(ro.getSpaceNodeId()).needRole(RoleConstants.SpaceNode.MANAGER);
        EditRoleResultVo result = nodeRoleUpdateManager.updateNodeRole(userId, spaceId, ro.getSpaceNodeId(), ro.getRole(), List.of(ro.getUnitId()));
        return ResponseData.success(result);
    }

    @PostResource(path = "/batchEditRole", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Batch edit node role")
    public ResponseData<EditRoleResultVo> batchEditRole(@RequestBody @Valid BatchModifyNodeRoleRo ro) {
        String spaceId = SpaceHolder.get();
        Long userId = SessionContext.getUserId();
        //pre-check current operator has permission and unit ids in current space
