/**
 * 小组权限查询结果，包含 teamId->role 和 teamId->unitId 两个映射
 */
private record TeamRoleMaps(Map<Long, String> teamIdToRole, Map<Long, Long> teamIdToUnitId) {
    static TeamRoleMaps empty() {
        return new TeamRoleMaps(Map.of(), Map.of());
    }
}

/**
 * 获取节点的小组权限映射 (teamId -> roleCode) 和 (teamId -> unitId)
 */
private TeamRoleMaps getTeamRoleMaps(String spaceId, Long spaceNodeId) {
    String controlId;
    if (controlService.existsByControlId(spaceNodeId.toString())) {
        controlId = spaceNodeId.toString();
    } else {
        Long extendNodeId = getNodeExtendNodeId(spaceNodeId);
        controlId = extendNodeId != null ? extendNodeId.toString() : null;
    }

    if (controlId == null) {
        return TeamRoleMaps.empty();
    }

    List<ControlRoleEntity> controlRoles = controlRoleService.getByControlId(controlId);
    if (CollectionUtils.isEmpty(controlRoles)) {
        return TeamRoleMaps.empty();
    }

    List<Long> unitIds = controlRoles.stream().map(ControlRoleEntity::getUnitId).toList();
    List<NodeRoleUnit> unitInfos = apitableGrpcClientService.getNodeRoleUnitList(spaceId, unitIds);

    // unitType=1 means Department/Team
    Map<Long, Long> unitIdToRefId = unitInfos.stream()
            .filter(u -> u.getUnitType() != null && u.getUnitType() == 1)
            .collect(Collectors.toMap(NodeRoleUnit::getUnitId, NodeRoleUnit::getUnitRefId, (a, b) -> a));

    Map<Long, String> unitIdToRole = controlRoles.stream()
            .collect(Collectors.toMap(ControlRoleEntity::getUnitId, ControlRoleEntity::getRoleCode, (a, b) -> a));

    // teamId(unitRefId) -> roleCode, teamId -> unitId
    Map<Long, String> teamIdToRole = new HashMap<>();
    Map<Long, Long> teamIdToUnitId = new HashMap<>();
    unitIdToRefId.forEach((unitId, teamId) -> {
        String role = unitIdToRole.get(unitId);
        if (role != null) {
            teamIdToRole.put(teamId, role);
        }
        teamIdToUnitId.put(teamId, unitId);
    });
    return new TeamRoleMaps(teamIdToRole, teamIdToUnitId);
}

