182→    private EditRoleResultVo checkMemberTeamConflict(String spaceId, Long spaceNodeId, String newRole, List<Long> unitIds) {
183→        List<NodeRoleUnit> unitInfos = apitableGrpcClientService.getNodeRoleUnitList(spaceId, unitIds);
184→        List<NodeRoleUnit> memberUnits = unitInfos.stream()
185→                .filter(u -> u.getUnitType() != null && u.getUnitType() == 3)
186→                .toList();
187→
188→        if (memberUnits.isEmpty()) {
189→            return EditRoleResultVo.noConflict();
190→        }
191→
192→        NodeRoleLevel newLevel = NodeRoleLevel.fromRoleTag(newRole);
193→
194→        // 批量收集所有成员关联的 unitId，减少 gRPC 调用次数
195→        Set<Long> allMemberUnitIds = new HashSet<>();
196→        for (NodeRoleUnit memberUnit : memberUnits) {
197→            List<Long> memberAllUnitIds = apitableGrpcClientService.getUnitsByMember(memberUnit.getUnitRefId(), spaceId);
198→            if (CollectionUtils.isNotEmpty(memberAllUnitIds)) {
199→                allMemberUnitIds.addAll(memberAllUnitIds);
200→            }
201→        }
202→        // 排除本次操作的 unitId
203→        allMemberUnitIds.removeAll(unitIds);
204→        if (allMemberUnitIds.isEmpty()) {
205→            return EditRoleResultVo.noConflict();
206→        }
207→
208→        // 一次性查询所有关联 unit 在该节点上的权限
209→        List<ControlRoleEntity> teamRoles = controlRoleService.getByControlIdAndUnitIds(
210→                spaceNodeId.toString(), new ArrayList<>(allMemberUnitIds));
211→
212→        // 找出权限高于本次设置的小组
213→        for (ControlRoleEntity teamRole : teamRoles) {
214→            NodeRoleLevel teamLevel = NodeRoleLevel.fromRoleTag(teamRole.getRoleCode());
215→            if (teamLevel.getLevel() > newLevel.getLevel()) {
216→                // 一次性查询冲突小组信息
217→                List<NodeRoleUnit> teamInfos = apitableGrpcClientService.getNodeRoleUnitList(spaceId, List.of(teamRole.getUnitId()));
218→                String teamName = CollectionUtils.isNotEmpty(teamInfos) ? teamInfos.getFirst().getUnitName() : "未知小组";
219→                String teamRoleDisplay = ROLE_DISPLAY_MAP.getOrDefault(teamRole.getRoleCode(), teamRole.getRoleCode());
220→
221→                return EditRoleResultVo.builder()
222→                        .hasConflict(true)
223→                        .conflictTeamName(teamName)
